/**
 * Template: provider pricing file
 */
import type { ProviderYaml } from './provider-yaml.types.js';

export function renderPricing(cfg: ProviderYaml): string {
  const key = cfg.name.toUpperCase().replace(/-/g, '_');
  const entries = Object.entries(cfg.models)
    .map(([m, p]) => `  '${m}': { input: ${p.input}, output: ${p.output} },`)
    .join('\n');

  return `/**
 * @generated by @flusk/cli — provider generator
 * ${cfg.displayName} pricing (USD per 1M tokens)
 */

export const ${key}_PRICING: Record<string, { input: number; output: number }> = {
${entries}
};
`;
}
